arguments.query:
CREATE TABLE IF NOT EXISTS model_calls (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  model TEXT NOT NULL,
  tier TEXT NOT NULL,
  note TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
INSERT INTO model_calls (model, tier) VALUES ('claude-sonnet-4.6', 'premium');
SELECT tier, COUNT(*) as n, GROUP_CONCAT(DISTINCT model) as models FROM model_calls GROUP BY tier;

